/**
 * Imports de folhas de estilo globais (ex.: `import "../styles/globals.css"` em `pages/_app.tsx`).
 * O TypeScript não conhece módulos `.css` por defeito; o Next compila-os, mas o `tsc` precisa desta declaração ambiente.
 * @see https://nextjs.org/docs/pages/building-your-application/configuring/typescript
 */
declare module "*.css";
